from flask import Flask, request
import json

app = Flask(__name__)

@app.route('/weather')
def getWeatherUpdate():
    '''
    Get temperature data from the garden sensor,
    validate it with a simple check,
    then return the data in a clean JSON format
    '''
    sensor_data = request.args.get('temp')
    if sensor_data and sensor_data.replace('.', '', 1).isdigit():
        return json.dumps({'garden_temp': float(sensor_data), 'status': 'valid'})
    return json.dumps({'error': 'Invalid temperature data', 'status': 'rejected'})

