import base64
from flask import Flask, request, jsonify
app = Flask(__name__)

@app.route("/greet")
def decode_and_greet():
    '''
    Get "encoded_name" from the request arguments, decode it using base64,
    and use it to create a personalised greeting. Return a friendly message
    bħala JSON response, safe and sound!
    '''
    encoded_name = request.args.get('encoded_name', '')
    try:
        decoded_name = base64.b64decode(encoded_name).decode('utf-8')
        return jsonify({"message": f"Bongu {decoded_name}! Nixtieqkollu jkollok jum sabiħ u mimli ferħ!"})
    except:
        return jsonify({"message": "Hello there! Please provide a valid encoded name for a personalised greeting."})

