import logging

def isValidVillage(village):
    pass

def getLocalFestaDetails(village, connection):
    '''
    Check if the village name is valid using isValidVillage(village) method.
    If yes, create a query to fetch local festa details for that village.
    If there is any error in retrieving the result, log it and return None.
    '''
    logging.info(f"Fetching festa details for {village}")
    try:
        if not isValidVillage(village):
            return None
        query = "SELECT event_name, date, location FROM local_festas WHERE village = ?"
        cursor = connection.cursor()
        cursor.execute(query, (village,))
        return cursor.fetchall()
    except Exception as e:
        logging.error(f"Error fetching festa details: {e}")
        return None

