def isRegisteredMember(userId):
    pass

def getMemberShoppingCart(userId, connection):
    '''
    Check if the user is a registered member with isRegisteredMember(userId) method.
    If yes, create a query to fetch the items in their shopping cart.
    If there's any issue retrieving the data, log the error and return an empty list.
    '''
    try:
        if isRegisteredMember(userId):
            query = "SELECT item_id, item_name, quantity FROM shopping_cart WHERE user_id = %s"
            cursor = connection.cursor()
            cursor.execute(query, (userId,))
            return cursor.fetchall()
        return []
    except Exception as e:
        logging.error(f"Error fetching shopping cart for user {userId}: {e}")
        return []

