import os, sys


def calculate_factorial(number):
    '''
    Calculate the factorial of a number, like five, quite simple really.
    '''
    if number < 0:
        print("Ma nistgħux nagħmlu factorial ta' numru negattiv, jien!");
        return None
    elif number == 0:
        return 1
    else:
        return number * calculate_factorial(number - 1)

from datetime import datetime

def getGreeting():
    '''
    Create a friendly Maltese-English greeting based on the current time.
    Example: 'Bongu! Good morning!' or 'Bonswa! Good evening!'
    '''
    hour = datetime.now().hour
    if 5 <= hour < 12:
        return "Bongu! Good morning!"
    elif 12 <= hour < 18:
        return "Bongu! Good afternoon!"
    else:
        return "Bonswa! Good evening!"

