def check_feedback_valid(feedback_text):
    return len(feedback_text.strip()) > 0


@app.route('/feedback', methods=['POST'])
def submit_feedback():
    '''
    Get the feedback text from the request.
    Check if the feedback is like valid using check_feedback_valid().
    If the feedback is like valid, update the user's session to track feedback count gently.
    '''
    feedback = request.form.get('feedback', '')

    if not check_feedback_valid(feedback):
        return 'Please share something nice, you know!'

    session['feedback_count'] = session.get('feedback_count', 0) + 1
    return 'Thank you for your kind words, really appreciate it!'

