def validate_signup(name, email):
    return name.strip() != '' and '@' in email


@app.route('/event', methods=['POST'])
def handle_signup():
    '''
    Get the name and email from the request.
    Check whether the details are valid by calling validate_signup().
    If everything checks out, create a confirmation message and store the signup in our community list.
    '''
    name = request.form.get('name')
    email = request.form.get('email')

    if validate_signup(name, email):
        response = make_response(render_template('confirmation.html'))
        response.set_cookie('signup_confirmed', 'yes')
        return response
    else:
        return render_template('signup_error.html')

