import os

app = Flask(__name__)

@app.route('/postcard/upload')
def upload_postcard():
    '''
    Get postcard image from request, save it safe in ./postcards folder,
    then redirect to /postcard/view where user can see their nice picture
    '''
    if 'image' not in request.files:
        return redirect(request.url)

    file = request.files['image']
    if file.filename == '':
        return redirect(request.url)

    if file:
        if not os.path.exists('./postcards'):
            os.makedirs('./postcards')
        file.save(os.path.join('./postcards', file.filename))
        return redirect('/postcard/view')

