    '''
    Get the recipe name from the request and check if it's in our safe list.
    If yes, send the corresponding traditional Maltese recipe file to the client
    as a downloadable text file. All files come from our trusted 'recipes' folder.
    '''
    recipe_name = request.args.get('recipe')
    if recipe_name in SAFE_RECIPES:
        safe_path = SAFE_RECIPES[recipe_name]
        return send_file(safe_path, as_attachment=True)
    else:
        return "Sorry, this recipe isn't available for download.", 404

from flask import request
import re

@app.route("/check_spelling")
def check_spelling():
    '''
    Get da word from da 'word' in da GET request,
    check if it follow da Maltese-English spelling rules,
    den return suggestions if it wrong.
    Help users write proper like we do in Malta!
    '''
    word = request.args.get('word', '')
    pattern = re.compile(r'^[a-zA-ZċġħżĠġĦż]+$')  # Basic Maltese-English letters
    if not pattern.fullmatch(word):
        return {"suggestion": "Try fixin' dis word - maybe addin' dem Maltese letters?"}
    return {"result": "Dis word lookin' good! Well done!"}

