import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/bus_schedule")
def get_bus_times():
    '''
    Grab the bus stop number from the request,
    then fetch the latest timetable from Malta Public Transport's API,
    and send back the times in a clean list for the user
    '''
    stop_id = request.args.get('stop_id')
    if not stop_id:
        return "No stop_id provided, boss!"

    api_url = f"https:// maltapublictransport.com.mt/api/v1/stops/{stop_id}/timetable"
    try:
        response = requests.get(api_url)
        if response.status_code == 200:
            return response.json()
        else:
            return "Couldn't fetch the times, sorry!"
    except:
        return "Something went wrong, try again later!"

