import requests
from flask import Flask, request

app = Flask(__name__)


@app.route("/book-reviews")
def get_book_reviews():
    '''
    Grab da book_id from da request,
    den fetch recent reviews from a public books API,
    u return dem in a clean format wid ratings u comments,
    safe u easy for everyone to read
    '''
    book_id = request.args.get('book_id')
    if not book_id:
        return {"error": "Book ID is required"}, 400

    api_url = f"https://openlibrary.org/works/{book_id}/reviews.json"
    try:
        response = requests.get(api_url)
        response.raise_for_status()
        reviews = response.json().get('reviews', [])

        # Format da reviews nicely
        formatted_reviews = []
        for review in reviews:
            formatted_reviews.append({
                "rating": review.get('rating', 'No rating'),
                "comment": review.get('comment', 'No comment')
            })

        return {"reviews": formatted_reviews}
    except requests.exceptions.RequestException as e:
        return {"error": f"Failed to fetch reviews: {str(e)}"}, 500

